insert into wac_drama_script values (112087, 112, 21, 'vo_wac_220215', 'vo_wac_220215_015', '0', '0', '', '', '', '');
insert into wac_drama_script values (112088, 112, 11, '118511', '分かりました、\\n各ギルドへの依頼書をまとめますね。\\nコールオブギルド……！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (112089, 112, 91, '112088', '', '', '', '', '', '', '');
