insert into wac_drama_script values (112098, 112, 11, '105811', 'わかりました！\r\\nそれじゃあわたしは、魔物料理の絵を――', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (112099, 112, 91, '112098', '', '', '', '', '', '', '');
insert into wac_drama_script values (112100, 112, 3, '105811', 'wac_215_peko_idle_wish', '1', '', '', '0.2', '', '');
