insert into wac_drama_script values (1112009, 1112, 11, '105311', 'よし、なかなかいい仕上がりだ！\\n絵を描くのも悪くないな！\\n時々子どものイタズラだと\\n思われるのは心外だが……', '10', '1', '1', '0', '0', '0.5');
