insert into wac_drama_script values (2112009, 2112, 11, '100511', 'じゃんじゃじゃ～ん！\\n自分、心を込めて描いたッス！\\n最初は不安もあったッスけど、\\nそんなのは邪魔なだけッスよね！', '10', '1', '1', '0', '0', '0.5');
