insert into wac_drama_script values (4212012, 4212, 11, '105211', 'と～～ってもかわいい絵が描けたわ♪\\n城壁にこんな絵が描いてあれば、\\nランドソルが素敵な場所って\\n伝わるわよね♪', '10', '1', '1', '0', '0', '0.5');
